CustomField.formula:
SUBSTITUTE( TRIM( IF(NOT(ISBLANK(FEC_Building__c)), FEC_Building__c & ", ", "") & IF(NOT(ISBLANK(FEC_Number__c)), FEC_Number__c & ", ", "") & IF(NOT(ISBLANK(FEC_Street__c)), FEC_Street__c & ", ", "") &
/* WARD */ IF( NOT(ISBLANK(FEC_Ward__c)), FEC_Ward__r.FEC_Name_VN__c & ", ", IF(NOT(ISBLANK(FEC_Ward_Text__c)), FEC_Ward_Text__c & ", ", "") ) &
/* DISTRICT */ IF( NOT(ISBLANK(FEC_District__c)), FEC_District__r.FEC_Name_VN__c & ", ", IF(NOT(ISBLANK(FEC_District_Text__c)), FEC_District_Text__c & ", ", "") ) &
/* PROVINCE */ IF( NOT(ISBLANK(FEC_Province__c)), FEC_Province__r.FEC_Name_VN__c & ", ", IF(NOT(ISBLANK(FEC_Province_Text__c)), FEC_Province_Text__c & ", ", "") ) &
/* COUNTRY */ IF( NOT(ISBLANK(FEC_Country__c)), FEC_Country__r.FEC_Name_VN__c & ", ", IF(NOT(ISBLANK(FEC_Country_Text__c)), FEC_Country_Text__c & ", ", "") ) &
IF(NOT(ISBLANK(FEC_ZipCode__c)), FEC_ZipCode__c, "") ), ", ,", "," )
